import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const g=JSON.parse('{"title":"北京推荐旅游路线","description":"","frontmatter":{},"headers":[],"relativePath":"guide/routes.md","filePath":"guide/routes.md","lastUpdated":null}'),i={name:"guide/routes.md"};function o(n,t,d,s,h,u){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="北京推荐旅游路线" tabindex="-1">北京推荐旅游路线 <a class="header-anchor" href="#北京推荐旅游路线" aria-label="Permalink to &quot;北京推荐旅游路线&quot;">​</a></h1><blockquote><p>&quot;条条大路通北京，步步皆是好风光。&quot;</p></blockquote><h2 id="按天数规划" tabindex="-1">按天数规划 <a class="header-anchor" href="#按天数规划" aria-label="Permalink to &quot;按天数规划&quot;">​</a></h2><h3 id="一日游-经典打卡" tabindex="-1">一日游（经典打卡） <a class="header-anchor" href="#一日游-经典打卡" aria-label="Permalink to &quot;一日游（经典打卡）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">时间</th><th style="text-align:left;">景点</th><th style="text-align:left;">活动</th></tr></thead><tbody><tr><td style="text-align:center;">6:00</td><td style="text-align:left;">天安门广场</td><td style="text-align:left;">看升旗仪式</td></tr><tr><td style="text-align:center;">8:30</td><td style="text-align:left;">故宫</td><td style="text-align:left;">从午门进入</td></tr><tr><td style="text-align:center;">12:00</td><td style="text-align:left;">景山</td><td style="text-align:left;">登景山俯瞰</td></tr><tr><td style="text-align:center;">14:00</td><td style="text-align:left;">北海公园</td><td style="text-align:left;">白塔、九龙壁</td></tr><tr><td style="text-align:center;">16:00</td><td style="text-align:left;">什刹海</td><td style="text-align:left;">胡同游</td></tr><tr><td style="text-align:center;">18:00</td><td style="text-align:left;">晚餐</td><td style="text-align:left;">后海或南锣鼓巷</td></tr></tbody></table><p><strong>门票预算</strong>：约72元</p><hr><h3 id="两日游-精华深度" tabindex="-1">两日游（精华深度） <a class="header-anchor" href="#两日游-精华深度" aria-label="Permalink to &quot;两日游（精华深度）&quot;">​</a></h3><h4 id="day-1-皇城精华" tabindex="-1">Day 1：皇城精华 <a class="header-anchor" href="#day-1-皇城精华" aria-label="Permalink to &quot;Day 1：皇城精华&quot;">​</a></h4><ul><li>天安门广场 → 故宫 → 景山 → 北海 → 什刹海</li></ul><h4 id="day-2-园林与学府" tabindex="-1">Day 2：园林与学府 <a class="header-anchor" href="#day-2-园林与学府" aria-label="Permalink to &quot;Day 2：园林与学府&quot;">​</a></h4><ul><li>颐和园 → 圆明园 → 清华/北大 → 鸟巢水立方</li></ul><p><strong>门票预算</strong>：约157元</p><hr><h3 id="三日游-经典全览" tabindex="-1">三日游（经典全览） <a class="header-anchor" href="#三日游-经典全览" aria-label="Permalink to &quot;三日游（经典全览）&quot;">​</a></h3><h4 id="day-1-皇城文化" tabindex="-1">Day 1：皇城文化 <a class="header-anchor" href="#day-1-皇城文化" aria-label="Permalink to &quot;Day 1：皇城文化&quot;">​</a></h4><ul><li>天安门 → 故宫 → 景山 → 北海 → 什刹海</li></ul><h4 id="day-2-园林与学府-1" tabindex="-1">Day 2：园林与学府 <a class="header-anchor" href="#day-2-园林与学府-1" aria-label="Permalink to &quot;Day 2：园林与学府&quot;">​</a></h4><ul><li>颐和园 → 圆明园 → 清华/北大 → 奥林匹克公园</li></ul><h4 id="day-3-长城与十三陵" tabindex="-1">Day 3：长城与十三陵 <a class="header-anchor" href="#day-3-长城与十三陵" aria-label="Permalink to &quot;Day 3：长城与十三陵&quot;">​</a></h4><ul><li>八达岭长城 → 明十三陵 → 南锣鼓巷</li></ul><p><strong>门票预算</strong>：约260元</p><hr><h3 id="五日游-深度体验" tabindex="-1">五日游（深度体验） <a class="header-anchor" href="#五日游-深度体验" aria-label="Permalink to &quot;五日游（深度体验）&quot;">​</a></h3><ul><li>Day 1：天安门 → 故宫 → 景山 → 北海</li><li>Day 2：颐和园 → 圆明园 → 清华/北大 → 鸟巢</li><li>Day 3：八达岭长城 → 明十三陵 → 王府井</li><li>Day 4：天坛 → 前门 → 国博 → 正阳门</li><li>Day 5：南锣鼓巷 → 什刹海 → 恭王府 → 钟鼓楼</li></ul><hr><h2 id="主题路线" tabindex="-1">主题路线 <a class="header-anchor" href="#主题路线" aria-label="Permalink to &quot;主题路线&quot;">​</a></h2><h3 id="皇城文化线" tabindex="-1">皇城文化线 <a class="header-anchor" href="#皇城文化线" aria-label="Permalink to &quot;皇城文化线&quot;">​</a></h3><p><strong>路线</strong>：天安门 → 故宫 → 景山 → 北海 → 天坛 → 颐和园 <strong>用时</strong>：2-3天</p><h3 id="胡同文化线" tabindex="-1">胡同文化线 <a class="header-anchor" href="#胡同文化线" aria-label="Permalink to &quot;胡同文化线&quot;">​</a></h3><p><strong>路线</strong>：南锣鼓巷 → 什刹海 → 烟袋斜街 → 钟鼓楼 → 恭王府 <strong>用时</strong>：1-2天</p><h3 id="近代历史线" tabindex="-1">近代历史线 <a class="header-anchor" href="#近代历史线" aria-label="Permalink to &quot;近代历史线&quot;">​</a></h3><p><strong>路线</strong>：天安门 → 人民英雄纪念碑 → 国博 → 北大红楼 → 圆明园 <strong>用时</strong>：1-2天</p><h3 id="亲子游线" tabindex="-1">亲子游线 <a class="header-anchor" href="#亲子游线" aria-label="Permalink to &quot;亲子游线&quot;">​</a></h3><p><strong>路线</strong>：故宫 → 科技馆 → 自然博物馆 → 天文馆 → 动物园 <strong>用时</strong>：2-3天</p><hr><p><strong>💡 Tips</strong>：北京景点众多，建议根据自己的时间和兴趣选择路线。第一次来北京，推荐选择&quot;三日游&quot;经典路线。</p>',37)])])}const y=a(i,[["render",o]]);export{g as __pageData,y as default};
